	this.timeline.addTween(cjs.Tween.get(this.button_link).wait(360));

	// Mask (mask)
	var mask = new cjs.Shape();
	mask._off = true;
	var mask_graphics_295 = new cjs.Graphics().p("EgZ1BQWIAA79MAzrAAAIAAb9g");

	this.timeline.addTween(cjs.Tween.get(mask).to({graphics:null,x:0,y:0}).wait(295).to({graphics:mask_graphics_295,x:141.9297,y:514.2043}).wait(65));

